// The synthetic det_<f> obligation has the shape
//
//     ({ &&& post1_self_.wf() && ... }) ==> det_schedule_blocked_thread_equal(...)
//
// The previous attempt failed at the cross-run `subtree_set` assertion for
// the *owning* container because the forall in the ensures is gated on
// `pre_self_.container_dom().contains(owning)`, which is only derivable
// from the well-formedness invariants `pre_self_.wf()` implies via
// `thread_inv()` / `endpoint_inv()`.  Call those broadcast-shaped lemmas
// up front, then open the antecedent in an `if`-branch where each ensures
// conjunct (for run 1 and run 2 alike) becomes a hypothesis and the
// per-pointer equalities can be co-triggered for the determinism check.

pre_self_.endpoint_inv();
pre_self_.thread_inv();

let victim_thread = pre_self_.get_endpoint(endpoint_ptr).queue@[0];

// From endpoint_inv: the head of the (non-empty) queue is in thread_dom.
// endpoint_inv has trigger `self.get_endpoint(e_ptr).queue@[i]`; the let-binding
// above writes exactly that term with i = 0, so the forall fires at endpoint_ptr / 0.
assert(pre_self_.endpoint_dom().contains(endpoint_ptr));
assert(pre_self_.get_endpoint(endpoint_ptr).queue.len() > 0);
assert(pre_self_.thread_dom().contains(victim_thread));

let owning = pre_self_.get_thread(victim_thread).owning_container;

// From thread_inv: every thread's owning_container is in container_dom.
assert(pre_self_.container_dom().contains(owning));

if (post1_self_.wf())
    && (post1_self_.page_closure() =~= pre_self_.page_closure())
    && (post1_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post1_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post1_self_.container_dom() == pre_self_.container_dom())
    && (post1_self_.thread_dom() == pre_self_.thread_dom())
    && (forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) ==>
            post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr) && container_ptr != owning
        ==>
        post1_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr)
        ==>
        post1_self_.get_container(container_ptr).subtree_set
            =~= pre_self_.get_container(container_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != victim_thread
        ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr)
        ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post1_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr)]
        post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
        ==> pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr)]
        post1_self_.endpoint_dom().contains(e_ptr)
        ==> pre_self_.get_endpoint(e_ptr).owning_container
            =~= post1_self_.get_endpoint(e_ptr).owning_container)
    && (post1_self_.get_thread(victim_thread).endpoint_descriptors
        =~= pre_self_.get_thread(victim_thread).endpoint_descriptors)
    && (post1_self_.get_container(owning).owned_procs
        =~= pre_self_.get_container(owning).owned_procs)
    && (post1_self_.get_container(owning).owned_threads
        =~= pre_self_.get_container(owning).owned_threads)
    && (post1_self_.get_container(owning).children
        =~= pre_self_.get_container(owning).children)
    && (post1_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1))
    && (post1_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads)
    && (post1_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter)
    && (post1_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state)
    && (post2_self_.wf())
    && (post2_self_.page_closure() =~= pre_self_.page_closure())
    && (post2_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post2_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post2_self_.container_dom() == pre_self_.container_dom())
    && (post2_self_.thread_dom() == pre_self_.thread_dom())
    && (forall|p_ptr: ProcPtr|
        #![trigger post2_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) ==>
            post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post2_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr) && container_ptr != owning
        ==>
        post2_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post2_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr)
        ==>
        post2_self_.get_container(container_ptr).subtree_set
            =~= pre_self_.get_container(container_ptr).subtree_set)
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != victim_thread
        ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr)
        ==> pre_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post2_self_.get_thread(t_ptr).endpoint_descriptors)
    && (forall|e_ptr: EndpointPtr|
        #![trigger post2_self_.get_endpoint(e_ptr)]
        post2_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr
        ==> pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
        #![trigger post2_self_.get_endpoint(e_ptr)]
        post2_self_.endpoint_dom().contains(e_ptr)
        ==> pre_self_.get_endpoint(e_ptr).owning_container
            =~= post2_self_.get_endpoint(e_ptr).owning_container)
    && (post2_self_.get_thread(victim_thread).endpoint_descriptors
        =~= pre_self_.get_thread(victim_thread).endpoint_descriptors)
    && (post2_self_.get_container(owning).owned_procs
        =~= pre_self_.get_container(owning).owned_procs)
    && (post2_self_.get_container(owning).owned_threads
        =~= pre_self_.get_container(owning).owned_threads)
    && (post2_self_.get_container(owning).children
        =~= pre_self_.get_container(owning).children)
    && (post2_self_.get_endpoint(endpoint_ptr).queue@
        == pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1))
    && (post2_self_.get_endpoint(endpoint_ptr).owning_threads
        == pre_self_.get_endpoint(endpoint_ptr).owning_threads)
    && (post2_self_.get_endpoint(endpoint_ptr).rf_counter
        == pre_self_.get_endpoint(endpoint_ptr).rf_counter)
    && (post2_self_.get_endpoint(endpoint_ptr).queue_state
        == pre_self_.get_endpoint(endpoint_ptr).queue_state)
{
    // ---- Inside the branch the full ensures-antecedent is a hypothesis. ----

    // (1) Domain equalities transit through `pre_self_`.
    assert(post1_self_.container_dom() == post2_self_.container_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.thread_dom() == post2_self_.thread_dom());
    assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
    assert(post1_self_.page_closure() =~= post2_self_.page_closure());

    // (2) Cross-side pointwise equality of get_proc — both posts pin every
    //     proc to pre_self_.get_proc(...).
    assert forall|p_ptr: ProcPtr| pre_self_.proc_dom().contains(p_ptr) implies
        #[trigger] post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    };

    // (3) Cross-side pointwise equality of get_container away from `owning`.
    assert forall|c_ptr: ContainerPtr|
        pre_self_.container_dom().contains(c_ptr) && c_ptr != owning implies
        #[trigger] post1_self_.get_container(c_ptr)
            =~= post2_self_.get_container(c_ptr) by {
        assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
        assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    };

    // (4) subtree_set equality across runs for every container.
    assert forall|c_ptr: ContainerPtr| pre_self_.container_dom().contains(c_ptr) implies
        #[trigger] post1_self_.get_container(c_ptr).subtree_set
            =~= post2_self_.get_container(c_ptr).subtree_set by {
        assert(post1_self_.get_container(c_ptr).subtree_set
            =~= pre_self_.get_container(c_ptr).subtree_set);
        assert(post2_self_.get_container(c_ptr).subtree_set
            =~= pre_self_.get_container(c_ptr).subtree_set);
    };

    // (5) Cross-side pointwise equality of get_endpoint away from endpoint_ptr.
    assert forall|e_ptr: EndpointPtr|
        post1_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr implies
        #[trigger] post1_self_.get_endpoint(e_ptr)
            =~= post2_self_.get_endpoint(e_ptr) by {
        assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
    };

    // (6) owning_container of every endpoint equal across runs.
    assert forall|e_ptr: EndpointPtr| post1_self_.endpoint_dom().contains(e_ptr) implies
        #[trigger] post1_self_.get_endpoint(e_ptr).owning_container
            =~= post2_self_.get_endpoint(e_ptr).owning_container by {
        assert(pre_self_.get_endpoint(e_ptr).owning_container
            =~= post1_self_.get_endpoint(e_ptr).owning_container);
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr).owning_container
            =~= post2_self_.get_endpoint(e_ptr).owning_container);
    };

    // (7) Cross-side pointwise equality of get_thread away from victim_thread.
    assert forall|t_ptr: ThreadPtr|
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != victim_thread implies
        #[trigger] post1_self_.get_thread(t_ptr)
            =~= post2_self_.get_thread(t_ptr) by {
        assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
        assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
    };

    // (8) endpoint_descriptors of every thread equal across runs.
    assert forall|t_ptr: ThreadPtr| pre_self_.thread_dom().contains(t_ptr) implies
        #[trigger] post1_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post2_self_.get_thread(t_ptr).endpoint_descriptors by {
        assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post1_self_.get_thread(t_ptr).endpoint_descriptors);
        assert(pre_self_.get_thread(t_ptr).endpoint_descriptors
            =~= post2_self_.get_thread(t_ptr).endpoint_descriptors);
    };

    // (9) Endpoint at endpoint_ptr: every component pinned to pre.
    assert(post1_self_.get_endpoint(endpoint_ptr).queue@
        == post2_self_.get_endpoint(endpoint_ptr).queue@);
    assert(post1_self_.get_endpoint(endpoint_ptr).owning_threads
        == post2_self_.get_endpoint(endpoint_ptr).owning_threads);
    assert(post1_self_.get_endpoint(endpoint_ptr).rf_counter
        == post2_self_.get_endpoint(endpoint_ptr).rf_counter);
    assert(post1_self_.get_endpoint(endpoint_ptr).queue_state
        == post2_self_.get_endpoint(endpoint_ptr).queue_state);
    assert(post1_self_.endpoint_dom().contains(endpoint_ptr));
    assert(post2_self_.endpoint_dom().contains(endpoint_ptr));
    assert(post1_self_.get_endpoint(endpoint_ptr).owning_container
        =~= post2_self_.get_endpoint(endpoint_ptr).owning_container);

    // (10) Owning container's preserved fields equal across runs.
    assert(post1_self_.get_container(owning).owned_procs
        =~= post2_self_.get_container(owning).owned_procs);
    assert(post1_self_.get_container(owning).owned_threads
        =~= post2_self_.get_container(owning).owned_threads);
    assert(post1_self_.get_container(owning).children
        =~= post2_self_.get_container(owning).children);
    assert(post1_self_.get_container(owning).subtree_set
        =~= post2_self_.get_container(owning).subtree_set);

    // (11) victim_thread's endpoint_descriptors equal across runs.
    assert(post1_self_.get_thread(victim_thread).endpoint_descriptors
        =~= post2_self_.get_thread(victim_thread).endpoint_descriptors);
}
